const ordinalNumber = (dirtyNumber, options) => {
  const number = Number(dirtyNumber);
  const unit = options?.unit;

  if (unit === "quarter") {
    // many news outlets use "quÃ― I"...
    switch (number) {
      case 1:
        return "I";
      case 2:
        return "II";
      case 3:
        return "III";
      case 4:
        return "IV";
    }
  } else if (unit === "day") {
    // day of week in Vietnamese has ordinal number meaning,
    // so we should use them, else it'll sound weird
    switch (number) {
      case 1:
        return "tháŧĐ 2"; // meaning 2nd day but it's the first day of the week :D
      case 2:
        return "tháŧĐ 3"; // meaning 3rd day
      case 3:
        return "tháŧĐ 4"; // meaning 4th day and so on
      case 4:
        return "tháŧĐ 5";
      case 5:
        return "tháŧĐ 6";
      case 6:
        return "tháŧĐ 7";
      case 7:
        return "cháŧ§ nháš­t"; // meaning Sunday, there's no 8th day :D
    }
  } else if (unit === "week") {
    if (number === 1) {
      return "tháŧĐ nhášĨt";
    } else {
      return "tháŧĐ " + number;
    }
  } else if (unit === "dayOfYear") {
    if (number === 1) {
      return "Äáš§u tiÃŠn";
    } else {
      return "tháŧĐ " + number;
    }
  }

  // there are no different forms of ordinal numbers in Vietnamese
  return String(number);
};

