function dateOrdinalNumber(number, localeNumber) {
  if (number > 18 && number <= 31) {
    return localeNumber + "āĶķā§";
  } else {
    switch (number) {
      case 1:
        return localeNumber + "āĶēāĶū";
      case 2:
      case 3:
        return localeNumber + "āĶ°āĶū";
      case 4:
        return localeNumber + "āĶ āĶū";
      default:
        return localeNumber + "āĶ";
    }
  }
}

const ordinalNumber = (dirtyNumber, options) => {
  const number = Number(dirtyNumber);
  const localeNumber = numberToLocale(number);
  const unit = options?.unit;

  if (unit === "date") {
    return dateOrdinalNumber(number, localeNumber);
  }
  if (number > 10 || number === 0) return localeNumber + "āĶĪāĶŪ";

  const rem10 = number % 10;
  switch (rem10) {
    case 2:
    case 3:
      return localeNumber + "ā§";
    case 4:
      return localeNumber + "āĶ°ā§āĶĨ";
    case 6:
      return localeNumber + "āĶ·ā§āĶ ";
    default:
      return localeNumber + "āĶŪ";
  }
};

