const ordinalNumber = (dirtyNumber, options) => {
  const unit = String(options?.unit);
  const number = Number(dirtyNumber);
  let suffix;

  if (unit === "date") {
    if (number === 3 || number === 23) {
      suffix = "-Ņ";
    } else {
      suffix = "-Ðĩ";
    }
  } else if (unit === "minute" || unit === "second" || unit === "hour") {
    suffix = "-Ð°";
  } else {
    suffix = "-Ðđ";
  }

  return number + suffix;
};

